def create_ai_router(db, get_current_admin_user=None):
    """
    Crée le routeur pour les routes IA
    """
    router = APIRouter(prefix="/ai", tags=["Intelligence Artificielle"])

    # Initialiser le service avec la DB
    ai_service = init_groq_ai(db)

    # ==================== CHAT PUBLIC ====================

    @router.post("/chat", response_model=ChatResponse)
    async def chat_with_ai(request: ChatRequest):
        """
        Envoie un message à Léa et reçoit une réponse.
        """
        try:
            conversation_id = request.conversation_id
            if not conversation_id:
                conversation_id = f"conv_{datetime.utcnow().strftime('%Y%m%d%H%M%S')}_{id(request)}"

            try:
                user_type = UserType(request.user_type) if request.user_type else UserType.VISITOR
            except ValueError:
                user_type = UserType.VISITOR

            context = None
            if request.context:
                try:
                    context = ConversationContext(request.context)
                except ValueError:
                    pass

            response = await ai_service.chat(
                user_message=request.message,
                conversation_id=conversation_id,
                user_type=user_type,
                user_info=request.user_info,
                context=context
            )

            return ChatResponse(
                response=response,
                conversation_id=conversation_id,
                timestamp=datetime.utcnow().isoformat()
            )

        except Exception as e:
            logger.error(f"Error in chat endpoint: {e}")
            raise HTTPException(status_code=500, detail="Erreur lors de la communication avec l'IA")

    # ==================== NOTIFICATION FIN DE CONVERSATION ====================

    @router.post("/notify-end")
    async def notify_conversation_end(request: NotifyEndRequest, background_tasks: BackgroundTasks):
        """
        Notifie la fin d'une conversation — envoie un email récapitulatif.

        Appelé par le frontend quand :
        - L'utilisateur ferme le widget de chat
        - L'utilisateur reset la conversation
        - Timeout d'inactivité (côté frontend)
        """
        try:
            background_tasks.add_task(
                ai_service.send_conversation_notification,
                conversation_id=request.conversation_id,
                user_type=request.user_type or "visitor",
                user_info=request.user_info
            )
            return {"status": "notification_queued", "conversation_id": request.conversation_id}
        except Exception as e:
            logger.error(f"Error queuing notification: {e}")
            return {"status": "error", "detail": str(e)}

    # ==================== ROUTES ADMIN ====================

    @router.post("/analyze-sentiment", response_model=SentimentResponse)
    async def analyze_sentiment(
        request: SentimentRequest,
        current_user: dict = Depends(get_current_admin_user) if get_current_admin_user else None
    ):
        """Analyse le sentiment d'un texte."""
        try:
            result = await ai_service.analyze_sentiment(request.text)
            return SentimentResponse(**result)
        except Exception as e:
            logger.error(f"Error in sentiment analysis: {e}")
            raise HTTPException(status_code=500, detail="Erreur lors de l'analyse")

    @router.post("/assist-email", response_model=EmailAssistResponse)
    async def assist_email_response(
        request: EmailAssistRequest,
        current_user: dict = Depends(get_current_admin_user) if get_current_admin_user else None
    ):
        """Génère une suggestion de réponse à un email."""
        try:
            suggested = await ai_service.generate_email_response(
                original_email=request.original_email,
                context=request.context
            )
            if not suggested:
                raise HTTPException(status_code=500, detail="Impossible de générer une réponse")
            return EmailAssistResponse(suggested_response=suggested)
        except HTTPException:
            raise
        except Exception as e:
            logger.error(f"Error in email assist: {e}")
            raise HTTPException(status_code=500, detail="Erreur lors de la génération")

    @router.get("/conversation/{conversation_id}/summary", response_model=ConversationSummaryResponse)
    async def get_conversation_summary(
        conversation_id: str,
        current_user: dict = Depends(get_current_admin_user) if get_current_admin_user else None
    ):
        """Génère un résumé d'une conversation."""
        try:
            summary = await ai_service.summarize_conversation(conversation_id)
            return ConversationSummaryResponse(summary=summary, conversation_id=conversation_id)
        except Exception as e:
            logger.error(f"Error getting summary: {e}")
            raise HTTPException(status_code=500, detail="Erreur lors de la génération du résumé")

    @router.get("/conversation/{conversation_id}/history", response_model=ConversationHistoryResponse)
    async def get_conversation_history(
        conversation_id: str,
        current_user: dict = Depends(get_current_admin_user) if get_current_admin_user else None
    ):
        """Récupère l'historique complet d'une conversation."""
        history = ai_service.get_conversation_history(conversation_id)
        return ConversationHistoryResponse(
            conversation_id=conversation_id, messages=history, message_count=len(history)
        )

    @router.delete("/conversation/{conversation_id}")
    async def clear_conversation(
        conversation_id: str,
        current_user: dict = Depends(get_current_admin_user) if get_current_admin_user else None
    ):
        """Efface l'historique d'une conversation."""
        ai_service.clear_conversation(conversation_id)
        return {"message": f"Conversation {conversation_id} effacée"}

    # ==================== STATISTIQUES ====================

    @router.get("/stats")
    async def get_ai_stats(
        current_user: dict = Depends(get_current_admin_user) if get_current_admin_user else None
    ):
        """Récupère les statistiques d'utilisation de l'IA."""
        try:
            active_conversations = len(ai_service.conversations)

            if db:
                total_messages = await db.ai_conversations.count_documents({})
                today_start = datetime.utcnow().replace(hour=0, minute=0, second=0, microsecond=0)
                today_messages = await db.ai_conversations.count_documents({
                    "timestamp": {"$gte": today_start}
                })
                pipeline = [
                    {"$group": {"_id": "$user_type", "count": {"$sum": 1}}},
                    {"$sort": {"count": -1}}
                ]
                user_type_stats = await db.ai_conversations.aggregate(pipeline).to_list(length=10)
            else:
                total_messages = 0
                today_messages = 0
                user_type_stats = []

            return {
                "active_conversations": active_conversations,
                "total_messages": total_messages,
                "today_messages": today_messages,
                "user_type_distribution": {
                    item["_id"]: item["count"] for item in user_type_stats
                },
                "model": ai_service.model,
                "status": "operational"
            }
        except Exception as e:
            logger.error(f"Error getting AI stats: {e}")
            return {
                "active_conversations": len(ai_service.conversations),
                "status": "operational",
                "error": str(e)
            }

    # ==================== SANTÉ DU SERVICE ====================

    @router.get("/health")
    async def ai_health_check():
        """Vérifie que le service IA est opérationnel."""
        try:
            response = await ai_service.chat(
                user_message="Test",
                conversation_id="health_check",
                user_type=UserType.VISITOR
            )
            ai_service.clear_conversation("health_check")
            return {
                "status": "healthy",
                "model": ai_service.model,
                "api_connected": True,
                "timestamp": datetime.utcnow().isoformat()
            }
        except Exception as e:
            logger.error(f"AI health check failed: {e}")
            return {
                "status": "unhealthy",
                "error": str(e),
                "timestamp": datetime.utcnow().isoformat()
            }

    # ==================== ENDPOINTS RAG ====================

    @router.post("/rag/chat", response_model=RAGChatResponse)
    async def rag_chat(request: RAGChatRequest):
        """Chat avec le système RAG."""
        try:
            if not knowledge_base.is_loaded:
                return RAGChatResponse(
                    success=False, response="",
                    error="Base de connaissances non chargée. Veuillez contacter l'administrateur."
                )

            context_data = knowledge_base.get_context_for_llm(query=request.message, top_k=3)

            rag_prompt = f"""Tu es Léa, l'assistante IA de l'association ETF (En Toute Franchise), spécialiste du droit de la franchise depuis 1993.

CONTEXTE DE LA BASE DE CONNAISSANCES ETF :
{context_data['context']}

SOURCES UTILISÉES :
{', '.join([s['title'] for s in context_data['sources']]) if context_data['sources'] else 'Aucune source spécifique'}

RÈGLES :
1. Réponds en te basant sur le contexte fourni
2. Si le contexte ne contient pas l'information, dis-le clairement
3. Cite les sources quand c'est pertinent
4. Reste professionnelle et précise sur les aspects juridiques
5. Propose de contacter ETF pour les cas complexes

QUESTION DE L'UTILISATEUR :
{request.message}"""

            response = await ai_service.chat(
                user_message=rag_prompt,
                conversation_id=f"rag_{datetime.utcnow().timestamp()}",
                user_type=UserType.VISITOR
            )

            return RAGChatResponse(success=True, response=response, sources=context_data['sources'])

        except Exception as e:
            logger.error(f"RAG chat error: {e}")
            return RAGChatResponse(success=False, response="", error=str(e))

    @router.post("/rag/search")
    async def rag_search(request: RAGSearchRequest):
        """Recherche dans la base de connaissances sans appeler le LLM."""
        try:
            if not knowledge_base.is_loaded:
                raise HTTPException(status_code=503, detail="Base de connaissances non chargée")
            results = knowledge_base.search(query=request.query, top_k=request.top_k)
            return {"success": True, "query": request.query, "results": results, "total_found": len(results)}
        except Exception as e:
            logger.error(f"RAG search error: {e}")
            raise HTTPException(status_code=500, detail=str(e))

    @router.get("/rag/stats")
    async def rag_stats():
        """Statistiques de la base de connaissances."""
        try:
            stats = knowledge_base.get_stats()
            return {"success": True, **stats}
        except Exception as e:
            logger.error(f"RAG stats error: {e}")
            return {"success": False, "error": str(e)}

    @router.get("/rag/suggestions")
    async def rag_suggestions():
        """Retourne des questions suggérées."""
        try:
            suggestions = knowledge_base.get_suggested_questions()
            return {"success": True, "suggestions": suggestions}
        except Exception as e:
            logger.error(f"RAG suggestions error: {e}")
            return {
                "success": False,
                "suggestions": [
                    "Qu'est-ce que la Directive 2006 ?",
                    "Comment fonctionne la CDAC ?",
                    "Quels sont les avantages d'adhérer à ETF ?",
                    "Qu'est-ce que le DIP en franchise ?",
                    "Comment fonctionne la clause de non-concurrence ?"
                ]
            }

    @router.post("/rag/reload")
    async def rag_reload():
        """Recharge la base de connaissances depuis le fichier JSON."""
        try:
            success = knowledge_base.load_articles()
            if success:
                stats = knowledge_base.get_stats()
                return {"success": True, "message": "Base de connaissances rechargée avec succès", **stats}
            else:
                return {"success": False, "error": "Échec du rechargement de la base de connaissances"}
        except Exception as e:
            logger.error(f"RAG reload error: {e}")
            raise HTTPException(status_code=500, detail=str(e))

    return router

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { Button } from './ui/button';
import { Input } from './ui/input';
import { Badge } from './ui/badge';
import {
  MessageCircle,
  X,
  Send,
  Minimize2,
  User,
  Bot,
  Sparkles,
  Loader2,
  RefreshCw
} from 'lucide-react';
import { API_URL } from '../config/api';
import ReactMarkdown from 'react-markdown';

/**
 * ChatAIWidget - Widget de chat intelligent avec IA Claude (Anthropic)
 * 
 * Ce widget permet aux visiteurs et membres de discuter avec Léa,
 * l'assistante IA d'En Toute Franchise.
 * 
 * Props:
 * - userType: 'visitor' | 'member' | 'admin' | 'vip' | 'prospect' - Type d'utilisateur
 * - userInfo: { name, email, ... } - Infos utilisateur (optionnel)
 * - defaultOpen: boolean - Ouvrir le chat par défaut
 */
const ChatAIWidget = ({ 
  userType = 'visitor', 
  userInfo = null,
  defaultOpen = false 
}) => {
  const [isOpen, setIsOpen] = useState(defaultOpen);
  const [isMinimized, setIsMinimized] = useState(false);
  const [messages, setMessages] = useState([]);
  const [inputValue, setInputValue] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [conversationId, setConversationId] = useState(null);
  const [unreadCount, setUnreadCount] = useState(0);
  const [error, setError] = useState(null);

  const messagesEndRef = useRef(null);
  const inputRef = useRef(null);
  const inactivityTimerRef = useRef(null);

  // Notify backend that conversation ended (email report)
  const notifyConversationEnd = useCallback((convId) => {
    if (!convId) return;
    // Only notify if there were actual messages (beyond welcome)
    const storedMessages = sessionStorage.getItem('etf_ai_messages');
    if (storedMessages) {
      try {
        const msgs = JSON.parse(storedMessages);
        const userMsgs = msgs.filter(m => m.role === 'user');
        if (userMsgs.length === 0) return; // No user messages, skip
      } catch (e) { return; }
    } else {
      return;
    }

    // Fire-and-forget notification
    fetch(`${API_URL}/ai/notify-end`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        conversation_id: convId,
        user_type: userType,
        user_info: userInfo
      })
    }).catch(err => console.log('Notification send failed:', err));
  }, [userType, userInfo]);

  // Reset inactivity timer (5 minutes)
  const resetInactivityTimer = useCallback(() => {
    if (inactivityTimerRef.current) {
      clearTimeout(inactivityTimerRef.current);
    }
    inactivityTimerRef.current = setTimeout(() => {
      // After 5 min inactivity, send notification
      notifyConversationEnd(conversationId);
    }, 5 * 60 * 1000);
  }, [conversationId, notifyConversationEnd]);

  // Générer ou récupérer l'ID de conversation
  useEffect(() => {
    let storedId = sessionStorage.getItem('etf_ai_conversation_id');
    if (!storedId) {
      storedId = `conv_${Date.now()}_${Math.random().toString(36).substring(2, 9)}`;
      sessionStorage.setItem('etf_ai_conversation_id', storedId);
    }
    setConversationId(storedId);

    // Récupérer les messages stockés en session
    const storedMessages = sessionStorage.getItem('etf_ai_messages');
    if (storedMessages) {
      try {
        setMessages(JSON.parse(storedMessages));
      } catch (e) {
        console.error('Error parsing stored messages:', e);
      }
    }
  }, []);

  // Sauvegarder les messages en session
  useEffect(() => {
    if (messages.length > 0) {
      sessionStorage.setItem('etf_ai_messages', JSON.stringify(messages));
    }
  }, [messages]);

  // Scroll vers le bas quand nouveaux messages
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  // Reset unread count quand on ouvre le chat
  useEffect(() => {
    if (isOpen) {
      setUnreadCount(0);
      setTimeout(() => inputRef.current?.focus(), 100);
    }
  }, [isOpen]);

  // Send notification when user leaves page
  useEffect(() => {
    const handleBeforeUnload = () => {
      const convId = sessionStorage.getItem('etf_ai_conversation_id');
      if (convId) {
        // Use sendBeacon for reliability on page close
        const payload = JSON.stringify({
          conversation_id: convId,
          user_type: userType,
          user_info: userInfo
        });
        navigator.sendBeacon(`${API_URL}/ai/notify-end`, new Blob([payload], { type: 'application/json' }));
      }
    };

    window.addEventListener('beforeunload', handleBeforeUnload);
    return () => {
      window.removeEventListener('beforeunload', handleBeforeUnload);
      if (inactivityTimerRef.current) {
        clearTimeout(inactivityTimerRef.current);
      }
    };
  }, [userType, userInfo]);

  // Message de bienvenue au premier affichage
  useEffect(() => {
    if (isOpen && messages.length === 0) {
      const welcomeMessage = userInfo?.name 
        ? `Bonjour ${userInfo.name} ! 👋 Je suis Léa, l'assistante d'En Toute Franchise. Comment puis-je vous aider aujourd'hui ?`
        : `Bonjour ! 👋 Je suis Léa, l'assistante d'En Toute Franchise. Que vous soyez commerçant, artisan ou franchisé, je suis là pour répondre à vos questions. Comment puis-je vous aider ?`;

      setMessages([{
        id: 'welcome',
        role: 'assistant',
        content: welcomeMessage,
        timestamp: new Date()
      }]);
    }
  }, [isOpen, messages.length, userInfo?.name]);

  // Jouer un son de notification
  const playNotificationSound = useCallback(() => {
    try {
      const audioContext = new (window.AudioContext || window.webkitAudioContext)();
      const oscillator = audioContext.createOscillator();
      const gainNode = audioContext.createGain();

      oscillator.connect(gainNode);
      gainNode.connect(audioContext.destination);

      oscillator.frequency.value = 800;
      oscillator.type = 'sine';
      gainNode.gain.value = 0.15;

      oscillator.start();
      setTimeout(() => {
        oscillator.frequency.value = 1000;
      }, 80);
      setTimeout(() => {
        oscillator.stop();
        audioContext.close();
      }, 150);
    } catch (e) {
      console.log('Audio not supported');
    }
  }, []);

  // Envoyer un message à l'IA
  const sendMessage = async () => {
    if (!inputValue.trim() || isLoading) return;

    const userMessage = inputValue.trim();
    setInputValue('');
    setError(null);

    // Reset inactivity timer
    resetInactivityTimer();

    // Ajouter le message utilisateur
    const newUserMessage = {
      id: Date.now(),
      role: 'user',
      content: userMessage,
      timestamp: new Date()
    };
    setMessages(prev => [...prev, newUserMessage]);

    // Afficher l'indicateur de chargement
    setIsLoading(true);

    try {
      const response = await fetch(`${API_URL}/ai/chat`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          message: userMessage,
          conversation_id: conversationId,
          user_type: userType,
          user_info: userInfo,
          context: detectContext(userMessage)
        })
      });

      if (!response.ok) {
        throw new Error('Erreur de communication avec l\'IA');
      }

      const data = await response.json();

      // Ajouter la réponse de l'IA
      const aiMessage = {
        id: Date.now() + 1,
        role: 'assistant',
        content: data.response,
        timestamp: new Date(data.timestamp)
      };

      setMessages(prev => [...prev, aiMessage]);

      // Notification si chat fermé
      if (!isOpen) {
        setUnreadCount(prev => prev + 1);
        playNotificationSound();
      }

    } catch (error) {
      console.error('Error sending message:', error);
      setError('Désolée, je rencontre un problème. Réessayez dans quelques instants.');

      // Ajouter un message d'erreur
      setMessages(prev => [...prev, {
        id: Date.now() + 1,
        role: 'assistant',
        content: 'Désolée, je rencontre un petit problème technique. 😅 Vous pouvez réessayer ou nous contacter à entoutefranchise6@gmail.com',
        timestamp: new Date(),
        isError: true
      }]);
    } finally {
      setIsLoading(false);
    }
  };

  // Détecter le contexte de la question
  const detectContext = (message) => {
    const lower = message.toLowerCase();

    if (lower.includes('adhésion') || lower.includes('adherer') || lower.includes('membre') || lower.includes('prix') || lower.includes('tarif') || lower.includes('inscription')) {
      return 'adhesion';
    }
    if (lower.includes('événement') || lower.includes('formation') || lower.includes('webinaire') || lower.includes('rencontre')) {
      return 'events';
    }
    if (lower.includes('partenaire') || lower.includes('réduction') || lower.includes('offre')) {
      return 'partners';
    }
    if (lower.includes('problème') || lower.includes('bug') || lower.includes('marche pas') || lower.includes('erreur') || lower.includes('connexion')) {
      return 'support';
    }
    if (lower.includes('forum') || lower.includes('communauté') || lower.includes('mousquetaire') || lower.includes('discussion')) {
      return 'community';
    }
    if (lower.includes('juridique') || lower.includes('contrat') || lower.includes('avocat') || lower.includes('litige')) {
      return 'legal';
    }

    return 'general';
  };

  // Fermer le chat — envoie la notification
  const handleClose = () => {
    notifyConversationEnd(conversationId);
    setIsOpen(false);
  };

  // Nouvelle conversation — envoie la notification pour l'ancienne
  const resetConversation = () => {
    // Notify for the old conversation
    notifyConversationEnd(conversationId);

    const newId = `conv_${Date.now()}_${Math.random().toString(36).substring(2, 9)}`;
    sessionStorage.setItem('etf_ai_conversation_id', newId);
    sessionStorage.removeItem('etf_ai_messages');
    setConversationId(newId);
    setMessages([]);
    setError(null);
  };

  const handleKeyPress = (e) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      sendMessage();
    }
  };

  const formatTime = (timestamp) => {
    if (!timestamp) return '';
    const date = new Date(timestamp);
    return date.toLocaleTimeString('fr-FR', { hour: '2-digit', minute: '2-digit' });
  };

  return (
    <>
      {/* Bouton flottant */}
      {!isOpen && (
        <button
          onClick={() => setIsOpen(true)}
          className="fixed bottom-6 right-6 z-50 w-16 h-16 bg-gradient-to-br from-blue-600 to-indigo-700 hover:from-blue-700 hover:to-indigo-800 rounded-full shadow-2xl flex items-center justify-center transition-all hover:scale-110 group"
          title="Discuter avec Léa, notre assistante"
        >
          <div className="relative">
            <MessageCircle className="h-7 w-7 text-white" />
            <Sparkles className="absolute -top-1 -right-1 h-4 w-4 text-yellow-300 animate-pulse" />
          </div>
          {unreadCount > 0 && (
            <span className="absolute -top-1 -right-1 w-6 h-6 bg-red-500 text-white text-xs rounded-full flex items-center justify-center font-bold animate-bounce">
              {unreadCount}
            </span>
          )}
          {/* Tooltip */}
          <span className="absolute right-full mr-3 px-3 py-2 bg-gray-900 text-white text-sm rounded-lg opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap">
            Besoin d'aide ? 💬
          </span>
        </button>
      )}

      {/* Fenêtre de chat */}
      {isOpen && (
        <div 
          className={`fixed bottom-6 right-6 z-50 bg-white rounded-2xl shadow-2xl flex flex-col transition-all duration-300 ${
            isMinimized 
              ? 'w-72 h-16 sm:w-80' 
              : 'w-[calc(100vw-2rem)] sm:w-96 h-[600px] max-h-[80vh]'
          }`}
          style={{ 
            boxShadow: '0 25px 50px -12px rgba(0, 0, 0, 0.25), 0 0 0 1px rgba(0, 0, 0, 0.05)' 
          }}
        >
          {/* Header */}
          <div 
            className="flex items-center justify-between px-4 py-3 bg-gradient-to-r from-blue-600 to-indigo-700 rounded-t-2xl cursor-pointer"
            onClick={() => setIsMinimized(!isMinimized)}
          >
            <div className="flex items-center gap-3">
              <div className="relative">
                <div className="w-10 h-10 bg-white/20 backdrop-blur-sm rounded-full flex items-center justify-center">
                  <Bot className="h-6 w-6 text-white" />
                </div>
                <span className="absolute bottom-0 right-0 w-3 h-3 bg-green-400 rounded-full border-2 border-white"></span>
              </div>
              <div>
                <h3 className="font-semibold text-white flex items-center gap-2">
                  Léa
                  <Sparkles className="h-4 w-4 text-yellow-300" />
                </h3>
                <p className="text-xs text-blue-100">Assistante ETF • En ligne</p>
              </div>
            </div>
            <div className="flex items-center gap-1">
              <Button
                variant="ghost"
                size="sm"
                onClick={(e) => { e.stopPropagation(); resetConversation(); }}
                className="text-white/80 hover:text-white hover:bg-white/10"
                title="Nouvelle conversation"
              >
                <RefreshCw className="h-4 w-4" />
              </Button>
              <Button
                variant="ghost"
                size="sm"
                onClick={(e) => { e.stopPropagation(); setIsMinimized(!isMinimized); }}
                className="text-white/80 hover:text-white hover:bg-white/10"
              >
                <Minimize2 className="h-4 w-4" />
              </Button>
              <Button
                variant="ghost"
                size="sm"
                onClick={(e) => { e.stopPropagation(); handleClose(); }}
                className="text-white/80 hover:text-white hover:bg-white/10"
              >
                <X className="h-4 w-4" />
              </Button>
            </div>
          </div>

          {/* Corps du chat */}
          {!isMinimized && (
            <>
              {/* Zone de messages */}
              <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-gray-50">
                {messages.map((message) => (
                  <div
                    key={message.id}
                    className={`flex ${message.role === 'user' ? 'justify-end' : 'justify-start'}`}
                  >
                    <div className={`flex gap-2 max-w-[85%] ${message.role === 'user' ? 'flex-row-reverse' : ''}`}>
                      {/* Avatar */}
                      <div className={`w-8 h-8 rounded-full flex items-center justify-center flex-shrink-0 ${
                        message.role === 'user' 
                          ? 'bg-blue-600' 
                          : message.isError 
                            ? 'bg-red-100' 
                            : 'bg-gradient-to-br from-blue-500 to-indigo-600'
                      }`}>
                        {message.role === 'user' ? (
                          <User className="h-4 w-4 text-white" />
                        ) : (
                          <Bot className={`h-4 w-4 ${message.isError ? 'text-red-500' : 'text-white'}`} />
                        )}
                      </div>

                      {/* Bulle de message */}
                      <div className={`rounded-2xl px-4 py-2.5 ${
                        message.role === 'user'
                          ? 'bg-blue-600 text-white rounded-tr-sm'
                          : message.isError
                            ? 'bg-red-50 text-red-800 border border-red-200 rounded-tl-sm'
                            : 'bg-white text-gray-800 shadow-sm border border-gray-100 rounded-tl-sm'
                      }`}>
                        {message.role === 'assistant' ? (
                          <div className="prose prose-sm max-w-none">
                            <ReactMarkdown
                              components={{
                                p: ({ children }) => <p className="mb-2 last:mb-0">{children}</p>,
                                a: ({ href, children }) => (
                                  <a href={href} target="_blank" rel="noopener noreferrer" className="text-blue-600 underline hover:text-blue-800">
                                    {children}
                                  </a>
                                ),
                                ul: ({ children }) => <ul className="list-disc ml-4 mb-2">{children}</ul>,
                                ol: ({ children }) => <ol className="list-decimal ml-4 mb-2">{children}</ol>,
                                li: ({ children }) => <li className="mb-1">{children}</li>,
                                strong: ({ children }) => <strong className="font-semibold">{children}</strong>,
                                code: ({ children }) => <code className="bg-gray-100 px-1 py-0.5 rounded text-sm">{children}</code>,
                              }}
                            >
                              {message.content}
                            </ReactMarkdown>
                          </div>
                        ) : (
                          <p className="text-sm whitespace-pre-wrap">{message.content}</p>
                        )}
                        <span className={`text-xs mt-1 block ${
                          message.role === 'user' ? 'text-blue-200' : 'text-gray-400'
                        }`}>
                          {formatTime(message.timestamp)}
                        </span>
                      </div>
                    </div>
                  </div>
                ))}

                {/* Indicateur de frappe */}
                {isLoading && (
                  <div className="flex justify-start">
                    <div className="flex gap-2 max-w-[85%]">
                      <div className="w-8 h-8 rounded-full bg-gradient-to-br from-blue-500 to-indigo-600 flex items-center justify-center flex-shrink-0">
                        <Bot className="h-4 w-4 text-white" />
                      </div>
                      <div className="bg-white rounded-2xl rounded-tl-sm px-4 py-3 shadow-sm border border-gray-100">
                        <div className="flex items-center gap-1">
                          <span className="w-2 h-2 bg-gray-400 rounded-full animate-bounce" style={{ animationDelay: '0ms' }}></span>
                          <span className="w-2 h-2 bg-gray-400 rounded-full animate-bounce" style={{ animationDelay: '150ms' }}></span>
                          <span className="w-2 h-2 bg-gray-400 rounded-full animate-bounce" style={{ animationDelay: '300ms' }}></span>
                        </div>
                      </div>
                    </div>
                  </div>
                )}

                <div ref={messagesEndRef} />
              </div>

              {/* Zone de saisie */}
              <div className="p-4 border-t bg-white rounded-b-2xl">
                {error && (
                  <div className="mb-2 p-2 bg-red-50 text-red-600 text-xs rounded-lg">
                    {error}
                  </div>
                )}
                <div className="flex gap-2">
                  <Input
                    ref={inputRef}
                    value={inputValue}
                    onChange={(e) => setInputValue(e.target.value)}
                    onKeyPress={handleKeyPress}
                    placeholder="Écrivez votre message..."
                    disabled={isLoading}
                    className="flex-1 rounded-xl border-gray-200 focus:border-blue-500 focus:ring-blue-500"
                  />
                  <Button
                    onClick={sendMessage}
                    disabled={!inputValue.trim() || isLoading}
                    className="bg-blue-600 hover:bg-blue-700 rounded-xl px-4"
                  >
                    {isLoading ? (
                      <Loader2 className="h-5 w-5 animate-spin" />
                    ) : (
                      <Send className="h-5 w-5" />
                    )}
                  </Button>
                </div>
                <p className="text-xs text-gray-400 mt-2 text-center">
                  En Toute Franchise • <a href="/contact" className="text-blue-500 hover:underline">Contacter l'association</a>
                </p>
              </div>
            </>
          )}
        </div>
      )}
    </>
  );
};

export default ChatAIWidget;

